function validate(args, output) {
    const arr = args[0].slice();
    const n = arr.length;
    if (!Array.isArray(output)) return false;
    if (output.length > 10 * n) return false;
    for (const k of output) {
        if (!Number.isInteger(k) || k < 1 || k > n) return false;
        const part = arr.slice(0, k).reverse();
        for (let i = 0; i < k; i++) arr[i] = part[i];
    }
    const target = args[0].slice().sort((a, b) => a - b);
    for (let i = 0; i < n; i++) if (arr[i] !== target[i]) return false;
    return true;
}

