class Solution:
    def pancakeSort(self, arr):
        # Independent construction: same selection-by-flip strategy implemented
        # with explicit reversals; deterministic so it matches the references
        # byte-for-byte for the build cross-check.
        a = list(arr)
        flips = []
        def flip(k):
            a[:k] = a[:k][::-1]
        for size in range(len(a), 1, -1):
            mi = 0
            for i in range(size):
                if a[i] > a[mi]:
                    mi = i
            if mi == size - 1:
                continue
            if mi != 0:
                flip(mi + 1)
                flips.append(mi + 1)
            flip(size)
            flips.append(size)
        return flips

