class Solution:
    def pancakeSort(self, arr):
        a = list(arr)
        res = []
        for size in range(len(a), 1, -1):
            mi = max(range(size), key=lambda i: a[i])
            if mi == size - 1:
                continue
            if mi != 0:
                a[:mi + 1] = a[:mi + 1][::-1]
                res.append(mi + 1)
            a[:size] = a[:size][::-1]
            res.append(size)
        return res

