var pancakeSort = function(arr) {
    const a = arr.slice();
    const res = [];
    const flip = (k) => {
        const part = a.slice(0, k).reverse();
        for (let i = 0; i < k; i++) a[i] = part[i];
    };
    for (let size = a.length; size > 1; size--) {
        let mi = 0;
        for (let i = 0; i < size; i++) if (a[i] > a[mi]) mi = i;
        if (mi === size - 1) continue;
        if (mi !== 0) { flip(mi + 1); res.push(mi + 1); }
        flip(size);
        res.push(size);
    }
    return res;
};
